import { useContext, useState } from "react";
import { CartContext } from "../context/CartContext";

function Navbar() {
  const { cart, removeFromCart } = useContext(CartContext);
  const [showCart, setShowCart] = useState(false);

  return (
    <div style={styles.navbar}>
      <h2 style={styles.logo}>Mini E-commerce</h2>

      <div style={styles.cartContainer}>
        {/* Cart Icon */}
        <div onClick={() => setShowCart(!showCart)} style={styles.cartIcon}>
        </div>

        {/* Dropdown */}
        {showCart && (
          <div style={styles.dropdown}>
            <h4>Cart Items</h4>

            {cart.length === 0 ? (
              <p>No items</p>
            ) : (
              cart.map((item, index) => (
                <div key={index} style={styles.item}>
                  <span>{item.name}</span>
                  <button onClick={() => removeFromCart(index)}>
                    ❌
                  </button>
                </div>
              ))
            )}
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  navbar: {
    display: "flex",
    justifyContent: "space-between",
    padding: "15px 30px",
    backgroundColor: "#222",
    color: "white",
    position: "relative"
  },
  logo: {
    margin: 0
  },
  cartContainer: {
    position: "relative"
  },
  cartIcon: {
    cursor: "pointer",
    fontSize: "18px"
  },
  dropdown: {
    position: "absolute",
    right: 0,
    top: "40px",
    background: "white",
    color: "black",
    width: "250px",
    padding: "10px",
    borderRadius: "8px",
    boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
    zIndex: 100
  },
  item: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: "8px"
  }
};

export default Navbar;
